class ImagesController < ApplicationController
  require 'fileutils'

  def upload
    uploaded_io = params[:image]
    format = params[:format]
    size = params[:size]

    upload_path = Rails.root.join('public', 'uploads', uploaded_io.original_filename)
    File.open(upload_path, 'wb') do |file|
      file.write(uploaded_io.read)
    end

    convert_image(upload_path, format, size)
  end

  private

  def convert_image(image_path, format, size)
    output_path = Rails.root.join('public', 'uploads', "converted.#{format}")
    system("convert #{image_path} -resize #{size} #{output_path}")

    FileUtils.rm(image_path) if File.exist?(image_path)
  end
end